#include <bits/stdc++.h>
using namespace std;
const int N=1003;
int n,t,f[N][N],ans;
bool a[N][N];
int main(){
	scanf("%d%d",&n,&t);
	for(int i=0,x,y;i<t;i++){
		scanf("%d%d",&x,&y);
		a[x][y]=1;
	}
	for(int i=1;i<=n;i++)
		for(int j=1;j<=n;j++)
			if(!a[i][j])
				f[i][j]=min(f[i-1][j],min(f[i][j-1],f[i-1][j-1]))+1,ans=max(ans,f[i][j]);
	printf("%d",ans);
	return 0;
}
